class Solution:
    def maxRemovals(self, source, pattern, targetIndices):
        target = list(targetIndices)
        t = len(target)
        best = 0
        for mask in range(1 << t):
            removed = {target[i] for i in range(t) if (mask >> i) & 1}
            remaining = [ch for idx, ch in enumerate(source) if idx not in removed]
            pos = 0
            for ch in remaining:
                if pos < len(pattern) and ch == pattern[pos]:
                    pos += 1
            if pos == len(pattern):
                best = max(best, bin(mask).count('1'))
        return best

