class Solution:
    def maxRemovals(self, source, pattern, targetIndices):
        n = len(source)
        m = len(pattern)
        target = set(targetIndices)
        INF = float('inf')
        dp = [[0] * (m + 1) for _ in range(n + 1)]
        for j in range(m - 1, -1, -1):
            dp[n][j] = INF
        for i in range(n - 1, -1, -1):
            for j in range(m - 1, -1, -1):
                best = dp[i + 1][j]
                if source[i] == pattern[j]:
                    cost = 1 if i in target else 0
                    cand = cost + dp[i + 1][j + 1]
                    if cand < best:
                        best = cand
                dp[i][j] = best
        return len(target) - dp[0][0]

