var maxRemovals = function(source, pattern, targetIndices) {
    const n = source.length, m = pattern.length;
    const target = new Set(targetIndices);
    const INF = Infinity;
    const dp = new Array(n + 1);
    for (let i = 0; i <= n; i++) dp[i] = new Array(m + 1).fill(0);
    for (let j = m - 1; j >= 0; j--) dp[n][j] = INF;
    for (let i = n - 1; i >= 0; i--) {
        for (let j = m - 1; j >= 0; j--) {
            let best = dp[i + 1][j];
            if (source[i] === pattern[j]) {
                const cost = target.has(i) ? 1 : 0;
                const cand = cost + dp[i + 1][j + 1];
                if (cand < best) best = cand;
            }
            dp[i][j] = best;
        }
    }
    return target.size - dp[0][0];
};
